import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_INSTRUCTION = `
You are the "EAC Innovation Advisor," an AI assistant for the "Strengthening Women and Youth Innovation and Entrepreneurship in the EAC Region" project.
Your goal is to help women and youth entrepreneurs in East Africa (Burundi, DRC, Kenya, Rwanda, South Sudan, Uganda, Tanzania).

Key information about the project:
- Implemented by EASTECO under the COYWA program.
- Targets 1,600 entrepreneurs.
- Establishing hubs in Kigali and Kampala.
- Focusing on SDGs 5, 8, and 10.

When answering:
1. Be encouraging, professional, and regionally aware.
2. Provide advice on business scaling, innovation, or navigating the EAC ecosystem.
3. If asked about project specifics (like the 4 components), explain them clearly based on the project overview.
4. Keep responses concise and formatted with Markdown.
`;

export const getInnovationAdvice = async (prompt: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
        topP: 0.9,
      },
    });
    return response.text || "I'm sorry, I couldn't process that request at the moment.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "The Innovation Advisor is currently offline. Please try again later.";
  }
};

